// Extract modified and added files from the webhook payload
const webhookData = $input.first().json;
const commits = webhookData.body.commits || [];

// Get the first commit (most recent)
const firstCommit = commits[0] || {};

// Get modified and added files
const modifiedFiles = firstCommit.modified || [];
const addedFiles = firstCommit.added || [];

// Combine both arrays
const allChangedFiles = [...modifiedFiles, ...addedFiles];

// Map each file path to a new item with file_path field
const items = allChangedFiles.map(filePath => ({
  json: {
    file_path: filePath
  }
}));

// Return the array of items
return items;

