// Surgically insert comments into the original code at specified line numbers
const item = $input.item.json;

// Get the original decoded code
const originalCode = $('Decode Base64 Content').item.json.decodedContent;

// Get the generated comments from the AI agent
const generatedComments = item.output.comments || [];

// Split the original code into lines
const codeLines = originalCode.split('\n');

// Sort comments by line number in descending order to insert from bottom to top
// This prevents line number shifts as we insert
const sortedComments = generatedComments.sort((a, b) => b.lineNumber - a.lineNumber);

// Insert each comment at the specified line number
for (const comment of sortedComments) {
  const lineNumber = comment.lineNumber;
  const commentText = comment.commentText;

  // Validate line number
  if (lineNumber > 0 && lineNumber <= codeLines.length) {
    // Get the indentation of the target line
    const targetLine = codeLines[lineNumber - 1];
    const indentation = targetLine.match(/^\s*/)[0];

    // Format the comment with proper indentation
    const formattedComment = `${indentation}${commentText}`;

    // Insert the comment before the target line
    codeLines.splice(lineNumber - 1, 0, formattedComment);
  }
}

// Join the lines back together
const updatedCode = codeLines.join('\n');

// Return the updated code along with metadata
return {
  json: {
    updatedContent: updatedCode,
    commentsAdded: sortedComments.length,
    filePath: $('Get File Content').item.json.file_path
  }
};

const item = $input.item.json;

// Decode base64 content if encoding is base64
let decodedContent = item.content;
if (item.encoding === 'base64') {
  decodedContent = Buffer.from(item.content, 'base64').toString('utf-8');
}

// Return all original fields plus decoded content
return {
  json: {
    ...item,
    decodedContent: decodedContent
  }
};
